ContainedObjects.LuaScript:
function onLoad()
    for _, markerName in ipairs(Global.call("dice_types")) do
        self.addContextMenuItem("Set to " .. markerName, function(player_color)
            setMarker(player_color, markerName)
        end)
    end
end

function setMarker(player_color, markerName)
    local color =(Global.call("dice_colors"))[markerName] or {r=1, g=1, b=1}
    self.setColorTint(color)
    self.setName(markerName .. " Counter")
    Global.call("onDieSetIdentityRemote", {die=self, player_color=player_color, identity=markerName})
end

function onNumberTyped(player_color, number)
  Global.call("onDieSetValueRemote", {die=self, player_color=player_color, number=number})
end

