    self.setColorTint(color)
    self.setName(markerName .. " Counter")
    Global.call("onDieSetIdentityRemote", {die=self, player_color=player_color, identity=markerName})
end

function onNumberTyped(player_color, number)
  Global.call("onDieSetValueRemote", {die=self, player_color=player_color, number=number})
end

function onLoad()
  for _, markerName in ipairs(Global.call("token_types")) do
    self.addContextMenuItem(
      "Set to " .. markerName,
      function(player_color, position, object)
        setMarker(markerName, player_color)
      end
    )
  end
  self.addTag("StatusToken")
end

function setMarker(markerName, player_color)
  local color = (Global.call("token_colors"))[markerName] or {r=1, g=1, b=1}
  self.setColorTint(color)
  self.setName(markerName .. " Marker")

  if player_color then
    Global.call("onMarkerSetIdentityRemote", {
      marker = self,
      player_color = player_color
    })
  end
end

